UPDATE posts

    title = #{title},
    content = #{content},

        deleted_at = #{deletedAt},

    update_time = #{updateTime}

WHERE id = #{id}
AND user_id = #{userId}
AND deleted_at IS NULL

mapper.select:
SELECT p.id, p.title, p.like_count AS likes, p.comment_count AS comments, p.view_count AS views, p.create_time AS createTime, u.username, avatar_res.file_url AS avatar, cover_res.file_url AS cover, c.name AS category FROM posts p INNER JOIN user u ON p.user_id = u.id INNER JOIN categories c ON p.category_id = c.id LEFT JOIN resource_file avatar_res ON avatar_res.biz_type = 'AVATAR' AND avatar_res.biz_id = p.user_id LEFT JOIN resource_file cover_res ON cover_res.biz_type = 'POST_COVER' AND cover_res.biz_id = p.id WHERE p.deleted_at IS NULL AND p.post_status = 1 AND c.status = 1
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%'))
AND p.user_id = #{userId}
AND p.category_id = #{categoryId}
ORDER BY p.create_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT p.id, p.title, p.like_count AS likes, p.comment_count AS comments, p.view_count AS views, p.create_time AS createTime, u.username, avatar_res.file_url AS avatar, cover_res.file_url AS cover, c.name AS category, ( p.view_count * 0.1 + p.like_count * 1.0 + p.comment_count * 2.0 ) / POW( (UNIX_TIMESTAMP(NOW()) - UNIX_TIMESTAMP(p.create_time)) / 3600 + 2, 1.5 ) AS hot_score FROM posts p INNER JOIN user u ON p.user_id = u.id INNER JOIN categories c ON p.category_id = c.id LEFT JOIN resource_file avatar_res ON avatar_res.biz_type = 'AVATAR' AND avatar_res.biz_id = p.user_id LEFT JOIN resource_file cover_res ON cover_res.biz_type = 'POST_COVER' AND cover_res.biz_id = p.id WHERE p.deleted_at IS NULL AND p.post_status = 1 AND c.status = 1
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%'))
AND p.user_id = #{userId}
AND p.category_id = #{categoryId}
ORDER BY hot_score DESC LIMIT #{limit} OFFSET #{offset}

SELECT p.id, p.title, -- 1. 封面图：关联资源表，取第一张 cover_res.file_url AS coverImage, -- 2. 摘要：数据库层截取 content 前 80 字 (根据数据库类型调整函数) -- MySQL 用 SUBSTRING, PostgreSQL 用 SUBSTR SUBSTRING(p.content, 1, 80) AS summary, -- 3. 互动数据：注意别名要和 Java 字段名一致 (likeCount, commentCount) p.like_count AS likeCount, p.comment_count AS commentCount
FROM posts p LEFT JOIN resource_file cover_res ON cover_res.biz_type = 'POST_COVER' AND cover_res.biz_id = p.id WHERE p.deleted_at IS NULL AND p.user_id = #{userId}
AND p.post_status = 1 ORDER BY p.create_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM posts p INNER JOIN categories c ON p.category_id = c.id WHERE p.deleted_at IS NULL AND p.post_status = 1 AND c.status = 1
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%'))
AND p.user_id = #{userId}
AND p.category_id = #{categoryId}
